/*===============================
	CREACIÓN DE BASE DE DATOS
=================================*/

CREATE DATABASE IF NOT EXISTS logistics;  -- Esto crea la base de datos logistics
USE logistics; -- Para conectar con la base de datos que hemos creado

/*==========================================
	CREACIÓN DE TABLAS E INSERTAR DATOS
============================================*/

DROP TABLE IF EXISTS dim_customer;  -- Para que si una vez creada la tabla intentamos crearla otra vez, no dé error
CREATE TABLE dim_customer (     -- Creamos y definimos los datos de las columnas de la tabla
    customer_id INT PRIMARY KEY,
    customer_name VARCHAR(100),
    customer_email VARCHAR(100),
    customer_city VARCHAR(50),
    customer_country VARCHAR(50)
);


SELECT * FROM dim_customer;

DROP TABLE IF EXISTS dim_carrier;
CREATE TABLE dim_carrier (
    carrier_id INT PRIMARY KEY,
    carrier_name VARCHAR(100),
    carrier_type VARCHAR(50)
);



SELECT * FROM dim_carrier;


DROP TABLE IF EXISTS dim_destination;
CREATE TABLE dim_destination (
    destination_id INT PRIMARY KEY,
    city VARCHAR(50),
    country VARCHAR(50),
    region VARCHAR(50)
);


SELECT * FROM dim_destination;

DROP TABLE IF EXISTS dim_date;
CREATE TABLE dim_date (
    date_id INT PRIMARY KEY,
    full_date DATE
);


SELECT * FROM dim_date;


DROP TABLE IF EXISTS fact_shipments;
CREATE TABLE fact_shipments (
    shipment_id INT PRIMARY KEY,
    date_id INT,
    customer_id INT,
    carrier_id INT,
    destination_id INT,
    weight_kg DECIMAL(10,2),
    shipping_cost DECIMAL(10,2),
    delivery_time_days INT,

    FOREIGN KEY (date_id) REFERENCES dim_date(date_id),
    FOREIGN KEY (customer_id) REFERENCES dim_customer(customer_id),
    FOREIGN KEY (carrier_id) REFERENCES dim_carrier(carrier_id),
    FOREIGN KEY (destination_id) REFERENCES dim_destination(destination_id)
);




SELECT * FROM fact_shipments;

-- Esta tabla es sintética y cuando empecé a analizarla me di cuenta de que el coste por kg no parecía real, así que modifico la tabla original

UPDATE fact_shipments
SET weight_kg = weight_kg / 10;

SELECT * FROM fact_shipments;



